"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[36190],{29682:s=>{s.exports=JSON.parse('{"tag":{"label":"rat health","permalink":"/docs/tags/rat-health","allTagsPath":"/docs/tags","count":10,"items":[{"id":"Rats/illnesses-and-conditions/common-health-issues","title":"Common Health Issues in Rats","description":"An overview of the most common health issues affecting pet rats, focusing on the chronic nature of Mycoplasma respiratory infections, the high incidence of mammary tumors, and conditions like bumblefoot.","permalink":"/docs/Rats/illnesses-and-conditions/common-health-issues"},{"id":"Rats/health-and-wellness/dental-health","title":"Dental Health in Rats","description":"A guide to dental health in rats, focusing on the causes and prevention of incisor overgrowth (malocclusion) and the importance of providing a proper diet and chew toys.","permalink":"/docs/Rats/health-and-wellness/dental-health"},{"id":"Rats/health-and-wellness/eye-and-vision-issues","title":"Eye & Vision Issues in Rats","description":"A guide to common eye and vision issues in rats, explaining the significance of porphyrin (red tears) as a health indicator and discussing common infections and age-related blindness.","permalink":"/docs/Rats/health-and-wellness/eye-and-vision-issues"},{"id":"Rats/health-and-wellness/gi-health","title":"Gastrointestinal (GI) Health in Rats","description":"A guide to gastrointestinal (GI) health in rats, covering their omnivorous digestive system and the common causes of diarrhea, including diet, stress, and secondary effects from other illnesses.","permalink":"/docs/Rats/health-and-wellness/gi-health"},{"id":"Rats/illnesses-and-conditions/kidney-and-urinary-disorders","title":"Kidney and Urinary Disorders in Rats","description":"An in-depth guide to kidney and urinary disorders in rats, with a focus on Chronic Progressive Nephropathy (CPN), a common age-related disease.","permalink":"/docs/Rats/illnesses-and-conditions/kidney-and-urinary-disorders"},{"id":"Rats/illnesses-and-conditions/leptospirosis","title":"Leptospirosis in Rats","description":"An important guide to leptospirosis in rats, a zoonotic bacterial disease, explaining its transmission, signs, and the critical importance of hygiene for pet owners.","permalink":"/docs/Rats/illnesses-and-conditions/leptospirosis"},{"id":"Rats/health-and-wellness/parasites","title":"Parasites in Rats","description":"A guide to common parasites affecting pet rats, including the intense itching caused by fur mites and lice, and the importance of veterinary-prescribed treatment.","permalink":"/docs/Rats/health-and-wellness/parasites"},{"id":"Rats/health-and-wellness/respiratory-issues","title":"Respiratory Issues in Rats (Mycoplasmosis)","description":"An in-depth guide to chronic respiratory disease in pet rats, caused by Mycoplasma pulmonis, covering the signs, triggers, and lifelong management of this ubiquitous condition.","permalink":"/docs/Rats/health-and-wellness/respiratory-issues"},{"id":"Rats/care-and-husbandry/hairless-rats","title":"What to Know About Hairless Rats","description":"A guide to caring for hairless rats, explaining their genetic background, unique care needs regarding temperature, diet, and skin health, and common health issues.","permalink":"/docs/Rats/care-and-husbandry/hairless-rats"},{"id":"Rats/illnesses-and-conditions/worms","title":"Worms in Pet Rats","description":"A guide to common internal worms in pet rats, such as pinworms and tapeworms, explaining that they are often asymptomatic and how they are diagnosed and treated.","permalink":"/docs/Rats/illnesses-and-conditions/worms"}],"unlisted":false}}')}}]);